import{_ as t,o as e,c as n,a6 as s,nv as i,nw as o,bx as l,o9 as r,cn as h,nC as u}from"./chunks/framework.UYVGz2W_.js";const f=JSON.parse('{"title":"Thumbnails","description":"","frontmatter":{},"headers":[],"relativePath":"thumbnails/index.md","filePath":"thumbnails/index.md"}'),m={name:"thumbnails/index.md"};function p(d,a,c,b,_,g){return e(),n("div",null,[...a[0]||(a[0]=[s('<h1 id="thumbnails" tabindex="-1">Thumbnails <a class="header-anchor" href="#thumbnails" aria-label="Permalink to “Thumbnails”">​</a></h1><h2 id="add-thumbnails-manually" tabindex="-1">Add Thumbnails Manually <a class="header-anchor" href="#add-thumbnails-manually" aria-label="Permalink to “Add Thumbnails Manually”">​</a></h2><p>To define a preview as a thumbnail, the preview MUST have been uploaded as a revision.</p><p>Click on the status you want on the list page, then click the <strong>Preview</strong> button (1) on the right panel.</p><p><img src="'+i+'" alt="Thumbnail Button"></p><p>Once you click on the button, you can choose to pick the first or any frame. Once the frame is selected, the thumbnail appears, and the button turns gray.</p><p><img src="'+o+'" alt="Thumbnail Applied"></p><h2 id="add-thumbnails-automatically" tabindex="-1">Add Thumbnails Automatically <a class="header-anchor" href="#add-thumbnails-automatically" aria-label="Permalink to “Add Thumbnails Automatically”">​</a></h2><p>If you prefer to have your thumbnails populate automatically, you can navigate to the settings page from the production using the navigation menu.</p><p><img src="'+l+'" alt="Settings Menu"></p><p>On the <strong>Parameters</strong> tab, select <strong>set new preview as entity thumbnail automatically</strong>.</p><p><img src="'+r+'" alt="Settings Preview Auto"></p><p>Don&#39;t forget to <strong>Save</strong> changes when you are done. Now, as soon as you upload a preview, it will be used automatically as a thumbnail.</p><h2 id="batch-upload-previews-as-thumbnails" tabindex="-1">Batch Upload Previews (as Thumbnails) <a class="header-anchor" href="#batch-upload-previews-as-thumbnails" aria-label="Permalink to “Batch Upload Previews (as Thumbnails)”">​</a></h2><p>Use the <strong>Add Thumbnails</strong> button <img src="'+h+'" alt="Add Thumbnails Button"> on the global page to import thumbnails in bulk.</p><p><img src="'+u+'" alt="History"></p><p>A new pop-up opens and asks you to choose which task types the thumbnails are linked to.</p><p><strong>Thumbnails batch import accepts image files and video files</strong>. Only the first frame is used as the thumbnail for the video files.</p><p>In order for the thumbnails to be automatically links to the correct shot, you have to name your thumbnails as sequence_shot.</p><p>For example, if you your sequence is named <code>SEQ_001</code> and your shot is named <code>SH_001</code>, then your thumbnail filename should be <code>SEQ_001_SH_001</code>.</p>',20)])])}const v=t(m,[["render",p]]);export{f as __pageData,v as default};
